fn getSimulationChunkAndIncreaseRefCount(pos: chunk.ChunkPosition) ?*SimulationChunk {
	std.debug.assert(pos.voxelSize == 1);
	mutex.lock();
	defer mutex.unlock();
	if (simulationChunkHashMap.get(pos)) |ch| {
		ch.increaseRefCount();
		return ch;
