pub fn perspective(fovY: f32, aspect: f32, near: f32, far: f32) Mat4f { // zig fmt: off
	const tanY = std.math.tan(fovY*0.5);
	const tanX = aspect*tanY;
	return Mat4f{
		.rows = [4]Vec4f{
			Vec4f{1/tanX, 0,                          0,      0},
			Vec4f{0,      0,                          1/tanY, 0},
			Vec4f{0,      -(far + near)/(near - far), 0,      2*near*far/(near - far)},
			Vec4f{0,      1,                          0,      0},
		},
	};
} // zig fmt: on

